/**
 * ProgressionRepository unit tests
 *
 * Test Budget: 4 distinct behaviors × 2 = 8 max unit tests (using 4)
 * Behavior 1: getCurrentProgression() returns UserProgression when row exists
 * Behavior 2: getCurrentProgression() returns null when no row found
 * Behavior 3: findHistory() returns ProgressionEvent[] ordered by advanced_at DESC
 * Behavior 4: findHistory() returns empty array when user has no history
 *
 * Port-to-port: tests invoke through ProgressionPort (driving port) interface,
 * mock only the Supabase client (driven port boundary).
 */

import { describe, it, expect, vi } from "vitest";
import type { ProgressionPort } from "../../../src/ports/ProgressionPort.js";
import { ProgressionRepository } from "../../../src/repositories/ProgressionRepository.js";

// ---------------------------------------------------------------------------
// Mock builders — Supabase driven port boundary stubs
// ---------------------------------------------------------------------------

function buildGetCurrentProgressionMock(row: unknown | null) {
  const queryBuilder = {
    select: vi.fn().mockReturnThis(),
    eq: vi.fn().mockReturnThis(),
    single: vi.fn().mockResolvedValue(
      row ? { data: row, error: null } : { data: null, error: { code: "PGRST116" } }
    ),
  };
  return {
    from: vi.fn().mockReturnValue(queryBuilder),
    _queryBuilder: queryBuilder,
  };
}

function buildFindHistoryMock(rows: unknown[]) {
  const queryBuilder = {
    select: vi.fn().mockReturnThis(),
    eq: vi.fn().mockReturnThis(),
    order: vi.fn().mockResolvedValue({ data: rows, error: null }),
  };
  return {
    from: vi.fn().mockReturnValue(queryBuilder),
    _queryBuilder: queryBuilder,
  };
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe("ProgressionRepository (via ProgressionPort)", () => {
  /**
   * Behavior 1: getCurrentProgression() returns UserProgression when row exists
   */
  it("returns current UserProgression when the user has a progression record", async () => {
    const userId = "user-abc";
    const track = "push";
    const dbRow = {
      user_id: userId,
      track,
      current_exercise_id: "8a7ffc4a-5499-4661-9985-d69e548210df",
      updated_at: "2026-04-17T10:00:00Z",
    };

    const supabase = buildGetCurrentProgressionMock(dbRow);
    const port: ProgressionPort = new ProgressionRepository(supabase as unknown as import("@supabase/supabase-js").SupabaseClient);

    const result = await port.getCurrentProgression(userId, track);

    expect(result).not.toBeNull();
    expect(result!.userId).toBe(userId);
    expect(result!.track).toBe("push");
    expect(result!.currentExerciseId).toBe("8a7ffc4a-5499-4661-9985-d69e548210df");
    expect(result!.updatedAt).toBeInstanceOf(Date);
  });

  /**
   * Behavior 2: getCurrentProgression() returns null when no row found (PGRST116)
   */
  it("returns null when the user has no progression record for the track", async () => {
    const supabase = buildGetCurrentProgressionMock(null);
    const port: ProgressionPort = new ProgressionRepository(supabase as unknown as import("@supabase/supabase-js").SupabaseClient);

    const result = await port.getCurrentProgression("user-xyz", "pull");

    expect(result).toBeNull();
  });

  /**
   * Behavior 3: findHistory() returns ProgressionEvent[] ordered by advanced_at DESC
   */
  it("returns progression events ordered newest-first for a user with history", async () => {
    const userId = "user-abc";
    const track = "push";
    const dbRows = [
      {
        id: "evt-2",
        user_id: userId,
        from_exercise_id: "ex-1",
        to_exercise_id: "ex-2",
        advanced_at: "2026-04-10T12:00:00Z",
        qualifying_session_ids: ["sess-1", "sess-2"],
      },
      {
        id: "evt-1",
        user_id: userId,
        from_exercise_id: "ex-0",
        to_exercise_id: "ex-1",
        advanced_at: "2026-03-01T09:00:00Z",
        qualifying_session_ids: ["sess-0"],
      },
    ];

    const supabase = buildFindHistoryMock(dbRows);
    const port: ProgressionPort = new ProgressionRepository(supabase as unknown as import("@supabase/supabase-js").SupabaseClient);

    const events = await port.findHistory(userId, track);

    expect(events).toHaveLength(2);
    expect(events[0].id).toBe("evt-2");
    expect(events[0].fromExerciseId).toBe("ex-1");
    expect(events[0].toExerciseId).toBe("ex-2");
    expect(events[0].advancedAt).toBeInstanceOf(Date);
    expect(events[0].qualifyingSessionIds).toEqual(["sess-1", "sess-2"]);
    expect(events[1].id).toBe("evt-1");
  });

  /**
   * Behavior 4: findHistory() returns empty array when user has no history
   */
  it("returns empty array when the user has no advancement history", async () => {
    const supabase = buildFindHistoryMock([]);
    const port: ProgressionPort = new ProgressionRepository(supabase as unknown as import("@supabase/supabase-js").SupabaseClient);

    const events = await port.findHistory("user-new", "push");

    expect(events).toEqual([]);
  });
});

tests/unit/repositories/ExerciseReposito.source:
/**
 * ExerciseRepository unit tests
 *
 * Test Budget: 4 distinct behaviors × 2 = 8 max unit tests
 * Behavior 1: search() returns exercises matching a partial name (ilike)
 * Behavior 2: search() returns empty array for empty string query
 * Behavior 3: search("pike pushup") normalizes to "pike push-up" before querying
 * Behavior 4: search("PPP progression") normalizes to "pike push-up" before querying
 *
 * Port-to-port: tests invoke through ExercisePort (driving port) interface,
 * mock only the Supabase client (driven port boundary).
 */

import { describe, it, expect, vi } from "vitest";
import type { ExercisePort } from "../../../src/ports/ExercisePort.js";
import { ExerciseRepository } from "../../../src/repositories/ExerciseRepository.js";

// ---------------------------------------------------------------------------
// Mock Supabase client — driven port boundary stub
// ---------------------------------------------------------------------------

function buildMockSupabaseClient(rows: unknown[]) {
  const queryBuilder = {
    select: vi.fn().mockReturnThis(),
    ilike: vi.fn().mockReturnThis(),
    order: vi.fn().mockResolvedValue({ data: rows, error: null }),
  };
  return {
    from: vi.fn().mockReturnValue(queryBuilder),
    queryBuilder,
  };
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe("ExerciseRepository (via ExercisePort)", () => {
  /**
   * Behavior 1: search() returns exercises matching partial name query
   */
  it("returns exercises whose name contains the search query", async () => {
    const pikeRow = {
      id: "8a7ffc4a-5499-4661-9985-d69e548210df",
      slug: "pike-push-up-ppp",
      name: "Pike Push-up (PPP progression)",
      track: "push",
      chain_order: 6,
      rr_criteria: {
        targetReps: 8,
        targetSets: 3,
        minFormQuality: 3,
        consecutiveSessions: 2,
      },
      rr_wiki_url: "https://www.reddit.com/r/bodyweightfitness/wiki/kb/recommended_routine",
      version_tag: "rr-2024",
      created_at: "2026-04-17T13:35:03.323945+00:00",
    };

    const mockClient = buildMockSupabaseClient([pikeRow]);
    const repo: ExercisePort = new ExerciseRepository(mockClient);

    const results = await repo.search("pike");

    expect(results).toHaveLength(1);
    expect(results[0].name).toBe("Pike Push-up (PPP progression)");
    expect(results[0].track).toBe("push");
    expect(results[0].chainOrder).toBe(6);
    expect(results[0].criteria).not.toBeNull();
    expect(results[0].criteria!.targetReps).toBe(8);
    expect(results[0].criteria!.targetSets).toBe(3);
    expect(results[0].criteria!.minFormQuality).toBe(3);
    expect(results[0].criteria!.consecutiveSessions).toBe(2);
  });

  /**
   * Behavior 2: search() returns empty array when no results match
   */
  it("returns empty array when query matches no exercises", async () => {
    const mockClient = buildMockSupabaseClient([]);
    const repo: ExercisePort = new ExerciseRepository(mockClient);

    const results = await repo.search("zzznomatch");

    expect(results).toHaveLength(0);
  });

  /**
   * Behavior 3: search("pike pushup") normalizes to "pike push-up" before the ilike query
   */
  it("normalizes 'pike pushup' alias to 'pike push-up' before querying Supabase", async () => {
    const mockClient = buildMockSupabaseClient([]);
    const repo: ExercisePort = new ExerciseRepository(mockClient as never);

    await repo.search("pike pushup");

    expect(mockClient.queryBuilder.ilike).toHaveBeenCalledWith(
      "name",
      "%pike push-up%"
    );
  });

  /**
   * Behavior 4: search("PPP progression") normalizes to "pike push-up" before the ilike query
   */
  it("normalizes 'PPP progression' alias to 'pike push-up' before querying Supabase", async () => {
    const mockClient = buildMockSupabaseClient([]);
    const repo: ExercisePort = new ExerciseRepository(mockClient as never);

    await repo.search("PPP progression");

    expect(mockClient.queryBuilder.ilike).toHaveBeenCalledWith(
      "name",
      "%pike push-up%"
    );
  });
});

tests/unit/services/ReadinessEngine.test.source:
/**
 * ReadinessEngine unit tests
 * Test Budget: 3 behaviors × 2 = 6 max unit tests (3 used)
 *
 * Driving port: ReadinessEngine.calculate() — application service
 * Driven port boundary: supabaseClient.functions.invoke (mocked at port boundary)
 */

import { describe, it, expect, vi } from "vitest";
import { ReadinessEngine } from "../../../src/services/ReadinessEngine.js";
import type { ReadinessSignal } from "../../../src/types/index.js";

function makeSupabaseMock(invokeResult: { data: unknown; error: unknown }) {
  return {
    functions: {
      invoke: vi.fn().mockResolvedValue(invokeResult),
    },
  };
}

const SIGNAL_FIXTURE: ReadinessSignal = {
  state: "NOT_YET",
  criterion: { targetReps: 8, targetSets: 3, minFormQuality: 3, consecutiveSessions: 2, rrWikiUrl: "https://reddit.com/r/bodyweightfitness/wiki/kb/recommended_routine" },
  streakCurrent: 1,
  streakRequired: 2,
  nextExerciseId: null,
  nextExerciseName: null,
  formScoreHistory: [4],
  criterionSummary: "3×8 at form ≥3/5 for 2 consecutive sessions",
  rrWikiUrl: "https://reddit.com/r/bodyweightfitness/wiki/kb/recommended_routine",
};

describe("ReadinessEngine.calculate()", () => {
  it("calls the Edge Function with userId and exerciseId and returns the parsed signal", async () => {
    const client = makeSupabaseMock({ data: SIGNAL_FIXTURE, error: null });
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const engine = new ReadinessEngine(client as any);

    const result = await engine.calculate("user-1", "exercise-abc");

    expect(client.functions.invoke).toHaveBeenCalledWith("fn-readiness-engine", {
      body: { userId: "user-1", exerciseId: "exercise-abc" },
    });
    expect(result).toEqual(SIGNAL_FIXTURE);
  });

  it("returns null when Edge Function responds with null (no sessions for exercise)", async () => {
    const client = makeSupabaseMock({ data: null, error: null });
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const engine = new ReadinessEngine(client as any);

    const result = await engine.calculate("user-1", "exercise-abc");

    expect(result).toBeNull();
  });

  it("throws a descriptive error when Edge Function returns an error", async () => {
    const client = makeSupabaseMock({ data: null, error: { message: "Function not found" } });
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const engine = new ReadinessEngine(client as any);

    await expect(engine.calculate("user-1", "exercise-abc")).rejects.toThrow(
      "ReadinessEngine.calculate failed: Function not found"
    );
  });
});

tests/unit/services/SyncCoordinator.test.source:
/**
 * SyncCoordinator unit tests
 * Test Budget: 3 behaviors × 2 = 6 max unit tests (3 used)
 *
 * Driving port: SyncCoordinator.drain() and getStatus() — application service
 * Driven port boundary: sessionPort.sync() (mocked at port boundary)
 */

import { describe, it, expect, vi } from "vitest";
import { SyncCoordinator } from "../../../src/services/SyncCoordinator.js";
import type { SessionPort } from "../../../src/ports/SessionPort.js";
import type { ReadinessPort } from "../../../src/ports/ReadinessPort.js";

function makeSessionPortMock(syncResult = 1): SessionPort {
  return {
    create: vi.fn(),
    addEntry: vi.fn(),
    close: vi.fn(),
    sync: vi.fn().mockResolvedValue(syncResult),
    findByUserAndExercise: vi.fn(),
  } as unknown as SessionPort;
}

function makeReadinessPortMock(): ReadinessPort {
  return {
    calculate: vi.fn(),
  } as unknown as ReadinessPort;
}

describe("SyncCoordinator", () => {
  it("drain returns SyncStatus with pendingCount=0 and syncStatus=idle after draining", async () => {
    const sessionPort = makeSessionPortMock(1);
    const readinessPort = makeReadinessPortMock();
    const coordinator = new SyncCoordinator(sessionPort, readinessPort);

    const status = await coordinator.drain("user-123");

    expect(status.pendingCount).toBe(0);
    expect(status.syncStatus).toBe("idle");
  });

  it("drain calls sessionPort.sync with the correct userId", async () => {
    const sessionPort = makeSessionPortMock(0);
    const readinessPort = makeReadinessPortMock();
    const coordinator = new SyncCoordinator(sessionPort, readinessPort);

    await coordinator.drain("user-456");

    expect(sessionPort.sync).toHaveBeenCalledWith("user-456");
  });

  it("getStatus returns current sync status", async () => {
    const sessionPort = makeSessionPortMock(0);
    const readinessPort = makeReadinessPortMock();
    const coordinator = new SyncCoordinator(sessionPort, readinessPort);

    const status = coordinator.getStatus();

    expect(status.pendingCount).toBe(0);
    expect(status.syncStatus).toBe("idle");
  });
});
